+
+interface CollapsibleTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
+  /** Show built-in chevron icon */
+  showChevron?: boolean;
+  /** Position of chevron */
+  chevronPosition?: "left" | "right";
+  children: React.ReactNode;
