+      <div className="flex-1 text-left">{children}</div>
+      {showChevron && chevronPosition === "right" && (
+        <motion.div
+          animate={{ rotate: isOpen ? 180 : 0 }}
+          transition={springConfig}
+          className="flex-shrink-0 text-muted-foreground"
+        >
